import{L as e,W as t,b as n,d as r,m as i,t as a,v as o,y as s}from"./chunks/plugin-vue_export-helper.D3GSJjLW.js";const c=JSON.parse(`{"title":"OPDS to your e-ink reader","description":"","frontmatter":{"title":"OPDS to your e-ink reader","customDescription":"Guide on how to self-host your library to your Kindle","og":{"image":"https://i.wotaku.wiki/f/guide.png"}},"headers":[],"relativePath":"guides/manga/opds.md","filePath":"guides/manga/opds.md","lastUpdated":1781707036000}`);var l={name:`guides/manga/opds.md`},u={id:`enabling-opds`,tabindex:`-1`},d={id:`adding-the-repo-to-koreader`,tabindex:`-1`},f={id:`optimizing-files-using-kcc`,tabindex:`-1`};function p(a,c,l,p,m,h){let g=t(`NolebasePageProperties`),_=t(`Feedback`);return e(),i(`div`,null,[n(g),c[6]||=r(`p`,null,`OPDS (Open Publication Distribution System) is a open standardized distribution system that allows you to deliver books, articles, mangas, etc. Think of it like RSS but for books and articles.`,-1),c[7]||=r(`p`,null,[s(`OPDS is widely supported by most self-hosted library management systems, like Calibre, `),r(`a`,{href:`https://wiki.kavitareader.com/guides/features/opds/`,target:`_blank`,rel:`noreferrer`},`Kavita`),s(`, `),r(`a`,{href:`https://komga.org/docs/guides/opds/`,target:`_blank`,rel:`noreferrer`},`Komga`),s(` and `),r(`a`,{href:`https://github.com/9001/copyparty?tab=readme-ov-file#opds-feeds`,target:`_blank`,rel:`noreferrer`},`copyparty`),s(`, and we'll dive on how to enable it on the three of them, but it's usually enabled by default.`)],-1),c[8]||=r(`p`,null,`This guide will explain how to server your library available in your computer/server to your Kindle/Kobo device. We will be using the OPDS protocol as the main way of downloading our content to our device.`,-1),r(`h2`,u,[c[0]||=s(`Enabling OPDS `,-1),n(_,{heading:`Enabling OPDS`}),c[1]||=r(`a`,{class:`header-anchor`,href:`#enabling-opds`,"aria-label":`Permalink to “Enabling OPDS”`},`​`,-1)]),c[9]||=o(`<h3 id="calibre-desktop" tabindex="-1">Calibre (desktop) <a class="header-anchor" href="#calibre-desktop" aria-label="Permalink to “Calibre (desktop)”">​</a></h3><div class="steps"><ol><li><p>Connect/share -&gt; Start Content server</p><figure><img src="/open-source-software/ss/opds/connect-share.png" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure></li><li><p>If you click Connect/share again, you&#39;ll see Stop Content server [..., port ... HTTP]. This is the IP and the port where the Calibre server is being hosted.</p><figure><img src="/open-source-software/ss/opds/connect-share-enabled.png" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure></li><li><p>If you add a /opds to the URL, you can get the OPDS catalog of your Calibre library</p></li></ol></div><div class="info custom-block"><p class="custom-block-title">Calibre-web</p><p>If you only have calibre-web it&#39;s already enabled by default.</p></div><div class="tip custom-block"><p class="custom-block-title">Komga, Kavita and copyparty</p><p>Links to their respective guides are on the top of this guide.</p></div>`,4),r(`h2`,d,[c[2]||=s(`Adding the repo to KOReader `,-1),n(_,{heading:`Adding the repo to KOReader`}),c[3]||=r(`a`,{class:`header-anchor`,href:`#adding-the-repo-to-koreader`,"aria-label":`Permalink to “Adding the repo to KOReader”`},`​`,-1)]),c[10]||=o(`<div class="steps"><ol><li><p>Go to the file explorer inside KOReader and open the upside menu. Then click on <span class="i-ic-sharp-search"></span> -&gt; OPDS catalog</p><figure><img src="/open-source-software/ss/opds/koreader-opds-catalog.png" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure></li><li><p>Click on the top left + button</p><figure><img src="/open-source-software/ss/opds/koreader-inside-opds-catalog.png" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure></li><li><p>In the Catalog URL you need to type the OPDS url. The catalog name is up to your choice.</p><figure><img src="/open-source-software/ss/opds/koreader-adding-opds.png" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure></li><li><p>When clicking the catalog name, you&#39;ll get a menu where you can search through your content available on your library and download it.</p></li></ol></div>`,1),r(`h2`,f,[c[4]||=s(`Optimizing files using KCC `,-1),n(_,{heading:`Optimizing files using KCC`}),c[5]||=r(`a`,{class:`header-anchor`,href:`#optimizing-files-using-kcc`,"aria-label":`Permalink to “Optimizing files using KCC”`},`​`,-1)]),c[11]||=o(`<p>If you prefer using Kindle/Kobo reader for reading manga rather than the KOReader one, you should optimize the files before transferring them to your device or adding it to your library. We&#39;ll use <a href="https://github.com/ciromattia/kcc" target="_blank" rel="noreferrer"><strong>KCC</strong></a> for that.</p><div class="steps"><ol><li><p>Install KindleGen <a href="https://github.com/ciromattia/kcc?tab=readme-ov-file#kindlegen" target="_blank" rel="noreferrer">as KCC stands depending on your OS</a></p></li><li><p><a href="https://github.com/ciromattia/kcc?tab=readme-ov-file#downloads" target="_blank" rel="noreferrer">Install KCC</a></p></li><li><p>Open KCC</p></li><li><p>Select your device model</p></li><li><p>Drag the files you want to convert</p></li><li><p>Click Convert and wait</p></li><li><p>That&#39;s it! Output files are stored in the same place as input ones unless you click on the Output Folder checkmark and select it on the folder icon of the right.</p><figure><img src="/open-source-software/ss/opds/kcc-ui.png" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure></li></ol></div>`,2)])}var m=a(l,[[`render`,p]]);export{c as __pageData,m as default};